#include <memory>
#include <string>
#include <unordered_map>
#include <iostream>

struct Shape
{
    virtual ~Shape() = default;
    virtual double area() const = 0;
};

struct Circle : Shape
{
    Circle(double r) : radius(r) {}
    double area() const override { return 3.14159265359 * radius * radius; }
    double radius;
};

struct Square : Shape
{
    Square(double s) : side(s) {}
    double area() const override { return side * side; }
    double side;
};

class ShapeFactory
{
private:
    struct Impl
    {
        std::unordered_map<std::string, std::function<std::unique_ptr<Shape>(double)>> creators;
        Impl()
        {
            creators["circle"] = [](double r) { return std::make_unique<Circle>(r); };
            creators["square"] = [](double s) { return std::make_unique<Square>(s); };
        }
    };
    std::unique_ptr<Impl> pImpl;

public:
    ShapeFactory() : pImpl(std::make_unique<Impl>()) {}
    std::unique_ptr<Shape> create(const std::string& type, double param) const
    {
        auto it = pImpl->creators.find(type);
        if (it != pImpl->creators.end())
        {
            return it->second(param);
        }
        return nullptr;
    }
};

int main()
{
    ShapeFactory factory;
    auto circle = factory.create("circle", 5.0);
    auto square = factory.create("square", 4.0);
    if (circle) std::cout << "Circle area: " << circle->area() << "\n";
    if (square) std::cout << "Square area: " << square->area() << "\n";
    return 0;
}
